head.script:
/**
 * 화 면 명 : 배부처리
 * 메뉴경로 : 회계/관리회계/실적관리/배부관리
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/co/rsltsmgnt/distmgnt/co_405_04_01b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-12-22
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항
 *    1. login정보 확인 필요 
 *     ☞  $c.data.getMemInfo() 처리
 *    2. [해결]<%@ page import="dbl.ac.am.constants.ACConstants" %> 상수가져오는건 공통에서 글로벌 상수로 변경할 듯. 
 *    3. 상수값 가져오는거 어떻게 할지? DGlobalValue.java 이런거 있을때마다 개발자가 DGlobalValue.js로 변경해서 올려야 하나?
 * 수정이력 :
 *    - 2025-12-22      배기원    최초작성
 */
//hidden 값
scwin.txtCoClsCd = "";  //회사구분코드

//전역변수
scwin.wrkNo    = "";    //작업구분코드
scwin.fromDate = "";    //작업날짜

//배부년월 초기값
scwin.today   = "";
scwin.closeYm = "";

scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;

//상수값(임시)
scwin.DGlobalValue = { "ALL": -1, "TRUE": 1, "FALSE": 0 };

scwin.initJson = {};        //초기세팅값(TOBE)
scwin.first = 0;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                   //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];             //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"]; //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];         //관리자권한

    const codeOptions = [
        { grpCd: "CO024", compID: "lc_distDegCd"}        //배부차수
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
    dlt_commonCodeCO024.sort("cd", 0);    
    scwin.initJson = dma_search.getJSON();
    scwin.first = 0;
};

/**
 * 조회 데이터셋 헤더 생성
 * TOBE 사용안함
 */
scwin.f_Header = function() {
    // var GAUCE_DATASET_HEADER = "distYm:STRING(6)" // 배부년월
    //     + ",distClsCd:STRING(1)" // 결산구분
    //     + ",distDegCd:STRING(1)" // 배부차수구분코드
    //     + ",ver:STRING(3)" // 버전
    //     + ",acctDeptCd:STRING(5)" // 부서
    //     + ",coCd:STRING(3)"; // 회사코드

    // ds_searchDistTarget.SetDataHeader(GAUCE_DATASET_HEADER);
    // ds_searchDistTarget.insertRow();
};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_distTarget.setNoResultMessageVisible(false);
    ds_distTarget.reform();
    ds_distTarget.removeAll();
    totalRows.setValue("0");
};


/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.setInit();
    scwin.f_Header();
    scwin.f_Reset();
    scwin.f_SetSrchDefault();
    scwin.f_setCompanyInfo();
};

/**
 * 조회초기 필드 Clear
 */
scwin.f_FieldClear = function (e) {
    $c.gus.cfInitObjects(tbl_search, [ed_coCd, ed_coNm, rd_distClsCd]);
    //dma_search.setJSON(scwin.initJson);
    scwin.f_SetDefault();
};
/**
 * 조회 기본값 설정
 */
scwin.f_SetSrchDefault = function() {
    scwin.today     = $c.date.getServerDateTime();
    scwin.closeYm   = scwin.today.substring(0,6);
    ica_fromDate.setCalendarValueType("yearMonth", {"displayFormat":"yyyy/MM"});
    ica_fromDate.setValue(scwin.closeYm);
    scwin.fromDate = ica_fromDate.getValue();
    rd_distClsCd.setValue("2");
    lc_distDegCd.setSelectedIndex(0);
    scwin.f_LoadVer();
    ica_fromDate.focus();
};

/**
 * 초기화 시
 */
scwin.f_SetDefault = function() {
    if(rd_distClsCd.getValue() == "1") {
        ica_fromDate.setCalendarValueType("year", {"displayFormat":"yyyy"});
        ica_fromDate.setValue(scwin.closeYm.substring(0, 4));
    }else {
        ica_fromDate.setCalendarValueType("yearMonth", {"displayFormat":"yyyy/MM"});
        ica_fromDate.setValue(scwin.closeYm);
    }
};

/**
 * 초기화 관련 변수 정의 함수
 */
scwin.f_Initial = function() {
    $c.gus.cfDisableKey();
};

/**
 * 저장 완료후 화면 Reset시 사용하는 함수 
 */
scwin.f_Reset = function() {
    scwin.f_Initial();
};

/**
* 조회버튼
*/
scwin.f_Retrieve = async function() {
    // 필수조건 확인
    let ret = await $c.gus.cfValidate([ica_fromDate, lc_version, rd_distClsCd, rd_distClsCd, ed_coCd]);
    if(!ret) {
        return false;
    }
    let date = ica_fromDate.getValue().trim();
    //계획일경우는 년도+"00", 실적일경우는 년월
    // 계획일경우
    if (rd_distClsCd.getValue() == "1") {
        if(ica_fromDate.getValue().length != 4){
            await $c.win.alert("배부년도은(는) 4자리수만큼 입력하십시오.");
            ica_fromDate.focus();
            return;
        }
        date = ica_fromDate.getValue()+"0101";
    // 실적배부일경우
    } else {
        if(ica_fromDate.getValue().length != 6){
            await $c.win.alert("배부년월은(는) 6자리수만큼 입력하십시오.");
            ica_fromDate.focus();
            return;
        }
        date = ica_fromDate.getValue()+"01";
    }

    ret = await $c.date.isDate(date);
    if(!ret) {
        await $c.win.alert("올바른 배부년월을(를) 입력하십시오.");
        ica_fromDate.focus();
        return;
    }
    //작업구분코드 및 날짜 세팅함수 호출
    ret = await scwin.f_setWrkNoFromDate();
    if(!ret) {
        return false;
    }

    scwin.setInit();
    dma_search.set("closeYm", scwin.fromDate);
    dma_search.set("closeDd", "00");
    dma_search.set("mgntNo" , "0");
    dma_search.set("wrkNo"  , scwin.wrkNo);
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_distTarget.setNoResultMessageVisible(true);
    ds_distTarget.setJSON(e.responseJSON.GAUCE);
    let rowCnt = ds_distTarget.getRowCount();
    totalRows.setValue(rowCnt);
    if (rowCnt > 0) {
        gr_distTarget.setFocusedCell(0, 0);
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
    }
};

// scwin.sbm_retrieve_submiterror = function (e) {
//     $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg)
// };


/**
 * Ver정보를 가져온다.
 */
scwin.f_LoadVer = async function () {
    //TODO : 초기값 세팅 시 lc_distDegCd이 값을 줘도 NULL이 되는 현상 때문에 추가
    if(!$c.gus.cfIsNull(lc_distDegCd.getValue())) {
        //작업구분코드 및 날짜 세팅함수 호출
        if(!await scwin.f_setWrkNoFromDate()) {
            return false;
        }
    }
    dma_search.set("sysCd"  , "CommonEBC");
    dma_search.set("queryId", "retrieveVersionInfo");
    dma_search.set("param1" , scwin.fromDate);
    dma_search.set("param2" , "");
    dma_search.set("param3" , "");
    dma_search.set("param4" , "");
    dma_search.set("param5" , "");
    ds_version.removeAll();
    let ret = await $c.sbm.execute(sbm_retrieveCommonPopup);
    ds_version.setJSON(ret.responseJSON.GAUCE);
    ds_version.reform();

    await scwin.f_SetFinalVer();
};


/**
 * 최종 Ver을 설정
 */
scwin.f_SetFinalVer = function() {
    if (ds_version.getRowCount() < 1) return;
    let index = 0;
    for (let i=0; i<ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == scwin.DGlobalValue.TRUE) {
            index = i;
            break;
        }
    }
    lc_version.setSelectedIndex(index);
};


/**
 * 마감체크
 */
scwin.f_JobCloseYN = async function () {
/*	(2006.05.03) 배부처리 시는 마감체크 안함.
	//cfJobCloseYN(마감요청구분,마감년월,마감일,작업번호,관리번호,리턴구분);
	var isClose = cfJobCloseYN("CUR",fromDate,"00",wrkNo,"0","ARR");
	// 선행마감 작업에 대한 검사
	if ( isClose[3] == "PRE" ) {
		if (isClose[0]=="1") {
			cfAlertMsg("선행작업 "+isClose[2]+"이 미마감되어서 현재 작업을 진행할 수 없습니다.");
			return false;
		} else if (isClose[0]=="0") {
			cfAlertMsg("선행작업 "+isClose[2]+"이 마감작업중이어서 현재 작업을 진행할 수 없습니다.");
			return false;
		} 
	} 

	// 해당마감 작업에 대한 검사
	if ( isClose[3] == "CUR" ) {
		if(isClose[0]=="0"){
			cfAlertMsg(isClose[2] + "(이)가 마감중입니다.");
			return false;
		 }else if(isClose[0]=="2"){
			cfAlertMsg(isClose[2] + "(이)가 마감완료가 되었습니다.");
			return false;
		}else {
			return true;
		}
	}
*/

    //작업구분코드 및 날짜 세팅함수 호출
    let ret = await scwin.f_setWrkNoFromDate();
    if(!ret) {
        return false;
    }
	return true;
};


/**
 * 조회 및 마감확인시 작업코드 날짜 세팅하는 함수
 */
scwin.f_setWrkNoFromDate = async function () {
	if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "1") {
		scwin.wrkNo = ACConstants.CLOSE_PLAN_DISTRIBUTION_1;
		scwin.fromDate = ica_fromDate.getValue().trim() + "00";
	} else if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "2") {
		scwin.wrkNo = ACConstants.CLOSE_PLAN_DISTRIBUTION_2;
		scwin.fromDate = ica_fromDate.getValue().trim() + "00";
	} else if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "3") {
		scwin.wrkNo = ACConstants.CLOSE_PLAN_DISTRIBUTION_3;
		scwin.fromDate = ica_fromDate.getValue().trim() + "00";	
	} else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "1") {
		scwin.wrkNo = ACConstants.CLOSE_RESULTS_DISTRIBUTION_1;
		scwin.fromDate = ica_fromDate.getValue().trim();
	} else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "2") {
		scwin.wrkNo = ACConstants.CLOSE_RESULTS_DISTRIBUTION_2;
		scwin.fromDate = ica_fromDate.getValue().trim();
	} else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "3") {
		scwin.wrkNo = ACConstants.CLOSE_RESULTS_DISTRIBUTION_3;
		scwin.fromDate = ica_fromDate.getValue().trim();		
	} else {
        await $c.win.alert("잘못된 조회 조건을 선택하셨습니다. 조회 조건을 확인하시기 바랍니다.");
		return false;
	}	
	return true;
};


/**
 * 마감년월 포커스 잃었을 시
 */
scwin.ica_fromDate_onblur = function (e) {
	scwin.f_LoadVer();
};


/**
 * 저장버튼
 */
scwin.f_Save = async function() {
	let msg = "";	// 메세지 저장

    let ret = await $c.gus.cfValidate([ica_fromDate, lc_version, lc_distDegCd, rd_distClsCd, ed_coCd]);
    if (!ret) {
        return false;
    }

	// 마감여부 확인(2006.05.03) 마감여부를 체크 하지 않음 주석처리 되어 있음.
	// wrkNo(마감구분코드)fromDate(년월)의 값을 세팅하기 위해서 호출은 해야함.
    ret = await scwin.f_JobCloseYN();
  	if (!ret) {
        return false;
    }
	// 배부처리 실행여부 확인
	await scwin.f_distCount();
    if (Number(ds_tempCount.getCellData(0, "col1")) > 0 ) {
		msg = "해당 조건의 배부처리를 실행하신적이 있습니다.<BR>배부처리를 재 실행 하시겠습니까?";
	} else {
		msg = "배부처리 Batch Job을 실행하시겠습니까?";
	}

    if ($c.gus.cfIsNull(lc_distDegCd.getValue())) {
        await $c.win.alert("실행시는 전체 조건을 선택하실수 없습니다.");
        lc_distDegCd.focus();
        return;
    }
    if (await $c.win.confirm(msg) ) {
	    sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg("배부처리 Batch Job이 정상적으로 실행되었습니다.");
        scwin.f_Retrieve(); 
    }
};

// scwin.sbm_save_submiterror = function (e) {
//     $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
// };


/**
 * 배부처리시 실행한적이 있는지 여부 확인
 */
scwin.f_distCount = async function () {
    var ebcId   = "";
    var queryId = "";
    var param1 = rd_distClsCd.getValue();	// 결산구분
    var param2 = lc_distDegCd.getValue();	// 차수
    var param3 = scwin.fromDate;					// 배부년월(계획은 년도+00, 실적은 입력된 년월임)
    var param4 = lc_version.getValue();		// 버전
    var param5 = ed_coCd.getValue();				// 회사코드

    if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "1") {
        ebcId = "DistributionEBC";
        queryId = "retrieveDistCount";
    } else if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "2") {
        ebcId = "DistributionEBC";
        queryId = "retrieveDistCount";
    } else if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "3") {
        ebcId = "DistributionEBC";
        queryId = "retrieveDistCount";	
    }else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "1") {
        ebcId = "DistributionEBC";
        queryId = "retrieveDistCount";
    }else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "2") {
        ebcId = "DistributionEBC";
        queryId = "retrieveDistCount";
    } else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "3") {
        ebcId = "DistributionEBC";
        queryId = "retrieveDistCount";		
    }
    // ds_tempCount.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd="+ebcId +
    //                                         "&queryId="+queryId +
    //                                         "&param1=" + param1 +
    //                                         "&param2=" + param2 +
    //                                         "&param3=" + param3 +
    //                                         "&param4=" + param4 +
    //                                         "&param5=" + param5;
    // ds_tempCount.Reset();

    dma_search.set("sysCd"  , ebcId);
    dma_search.set("queryId", queryId);
    dma_search.set("param1" , param1);
    dma_search.set("param2" , param2);
    dma_search.set("param3" , param3);
    dma_search.set("param4" , param4);
    dma_search.set("param5" , param5);
    ds_tempCount.removeAll();
    let ret = await $c.sbm.execute(sbm_retrieveCommonPopup);
    ds_tempCount.setJSON(ret.responseJSON.GAUCE);
    ds_tempCount.reform();
};

